const today = new Date();
const items = [];

for (const item of $input.all()) {
  const row = item.json;
  if (!row.ServiceDate || !row.Phone) continue;

  const serviceDate = new Date(row.ServiceDate);
  const monthsDiff = (today.getFullYear() - serviceDate.getFullYear()) * 12 
    + (today.getMonth() - serviceDate.getMonth());

  // Send at 6 months if not already sent
  const send6 = monthsDiff >= 6 && monthsDiff < 7 && row.Sent6Month === 'FALSE';
  // Send at 12 months if not already sent  
  const send12 = monthsDiff >= 12 && monthsDiff < 13 && row.Sent12Month === 'FALSE';

  if (send6 || send12) {
    items.push({ json: { ...row, sendMonth: send12 ? 12 : 6 } });
  }
}

return items;
